// A curated catalog of CDP effects exposed to consuming apps and tests.
//
// Each effect names a CDP program, an argument template, and its parameters.
// `domain: 'spectral'` effects are wrapped in a pvoc analysis/resynthesis chain;
// `mono: true` marks programs that only accept mono input, so multichannel
// sources are processed per channel and recombined (see applyEffect).
//
// Arg template tokens: '$IN'/'$OUT' (virtual file paths), '$IN2' (second source
// for `inputs: 2` effects), '$DATA' (a text data file generated by `data(values)`),
// a literal string, { p: 'name' } which is replaced by the named parameter's
// current value, or { p: 'name', flag: '-s' } which becomes the value attached to
// a flag, e.g. '-s0.5' (the form CDP uses for optional switches).

import { decodeAudio, encodeWav } from './wav.js';

